import { Injectable } from '@angular/core';
import { MatDialog } from '@angular/material/dialog';
import { Router } from '@angular/router';
import { Actions, ofType, createEffect } from '@ngrx/effects';
import { of } from 'rxjs';
import { catchError, exhaustMap, map, tap } from 'rxjs/operators';
import { LoginPageActions } from '@example-app/auth/actions/login-page.actions';
import { AuthApiActions } from '@example-app/auth/actions/auth-api.actions';
import { AuthActions } from '@example-app/auth/actions/auth.actions';
import { Credentials } from '@example-app/auth/models';
import { AuthService } from '@example-app/auth/services';
import { LogoutConfirmationDialogComponent } from '@example-app/auth/components';
import { UserActions } from '@example-app/core/actions/user.actions';

@Injectable()
export class AuthEffects {
  login$ = createEffect(() =>
    this.actions$.pipe(
      ofType(LoginPageActions.login),
      map((action) => action.credentials),
      exhaustMap((auth: Credentials) =>
        this.authService.login(auth).pipe(
          map((user) => AuthApiActions.loginSuccess({ user })),
          catchError((error) => of(AuthApiActions.loginFailure({ error })))
        )
      )
    )
  );

  loginSuccess$ = createEffect(
    () =>
      this.actions$.pipe(
        ofType(AuthApiActions.loginSuccess),
        tap(() => this.router.navigate(['/']))
      ),
    { dispatch: false }
  );

  loginRedirect$ = createEffect(
    () =>
      this.actions$.pipe(
        ofType(AuthApiActions.loginRedirect, AuthActions.logout),
        tap(() => {
          this.router.navigate(['/login']);
        })
      ),
    { dispatch: false }
  );

  logoutConfirmation$ = createEffect(() =>
    this.actions$.pipe(
      ofType(AuthActions.logoutConfirmation),
      exhaustMap(() => {
        const dialogRef = this.dialog.open<
          LogoutConfirmationDialogComponent,
          undefined,
          boolean
        >(LogoutConfirmationDialogComponent);

        return dialogRef.afterClosed();
      }),
      map((result) =>
        result ? AuthActions.logout() : AuthActions.logoutConfirmationDismiss()
      )
    )
  );

  logoutIdleUser$ = createEffect(() =>
    this.actions$.pipe(
      ofType(UserActions.idleTimeout),
      map(() => AuthActions.logout())
    )
  );

  constructor(
    private actions$: Actions,
    private authService: AuthService,
    private router: Router,
    private dialog: MatDialog
  ) {}
}

import { Component, computed, input } from '@angular/core';

import { TableColumnInternal } from '../../../types/internal.types';
import { DataTableBodyRowComponent } from '../body-row.component';

const defaultSumFunc = (cells: any[]): any => {
  const cellsWithValues = cells.filter(cell => !!cell);

  if (!cellsWithValues.length) {
    return null;
  }
  if (cellsWithValues.some(cell => typeof cell !== 'number')) {
    return null;
  }

  return cellsWithValues.reduce((res, cell) => res + cell);
};

const noopSumFunc = (cells: any[]): void => {
  return;
};

@Component({
  selector: 'datatable-summary-row',
  imports: [DataTableBodyRowComponent],
  template: `
    @let summaryRow = this.summaryRow();
    @let _internalColumns = this._internalColumns();
    @if (summaryRow && _internalColumns.length) {
      <datatable-body-row
        ariaRowCheckboxMessage=""
        [columns]="_internalColumns"
        [rowHeight]="rowHeight()"
        [row]="summaryRow"
        [rowIndex]="{ index: -1 }"
        [cssClasses]="{}"
      />
    }
  `,
  host: {
    class: 'datatable-summary-row'
  }
})
export class DataTableSummaryRowComponent {
  readonly rows = input.required<any[]>();
  readonly columns = input.required<TableColumnInternal[]>();

  readonly rowHeight = input.required<number>();
  readonly innerWidth = input.required<number>();

  protected readonly _internalColumns = computed(() => {
    return this.columns().map(col => ({
      ...col,
      cellTemplate: col.summaryTemplate
    }));
  });
  protected readonly summaryRow = computed(() => this.computeSummaryRowValues());

  private computeSummaryRowValues() {
    if (!this.columns().length || !this.rows().length) {
      return undefined;
    }
    const summaryRow: any = {};
    this.columns()
      .filter(col => !col.summaryTemplate && col.prop)
      .forEach(col => {
        const cellsFromSingleColumn = this.rows().map(row => row[col.prop!]);
        const sumFunc = this.getSummaryFunction(col);

        summaryRow[col.prop!] = col.pipe
          ? col.pipe.transform(sumFunc(cellsFromSingleColumn))
          : sumFunc(cellsFromSingleColumn);
      });

    return summaryRow;
  }

  private getSummaryFunction(column: TableColumnInternal): (a: any[]) => any {
    if (column.summaryFunc === undefined) {
      return defaultSumFunc;
    } else if (column.summaryFunc === null) {
      return noopSumFunc;
    } else {
      return column.summaryFunc;
    }
  }
}

import { Component, Input, Output, EventEmitter } from '@angular/core';
import { FormGroup, FormControl } from '@angular/forms';
import { Credentials } from '@example-app/auth/models';

@Component({
  selector: 'bc-login-form',
  template: `
    <mat-card>
      <mat-card-title>Login</mat-card-title>
      <mat-card-content>
        <form [formGroup]="form" (ngSubmit)="submit()">
          <p>
            <mat-form-field>
              <input
                type="text"
                matInput
                placeholder="Username"
                formControlName="username"
              />
            </mat-form-field>
          </p>

          <p>
            <mat-form-field>
              <input
                type="password"
                matInput
                placeholder="Password"
                formControlName="password"
              />
            </mat-form-field>
          </p>

          <p *ngIf="errorMessage" class="login-error">
            {{ errorMessage }}
          </p>

          <div class="login-buttons">
            <button type="submit" mat-button>Login</button>
          </div>
        </form>
      </mat-card-content>
    </mat-card>
  `,
  styles: [
    `
      :host {
        display: flex;
        justify-content: center;
        margin: 4.5rem 0;
      }

      .mat-mdc-form-field {
        width: 100%;
        min-width: 300px;
      }

      mat-card-title {
        text-align: center;
        margin: 1rem 0;
      }

      mat-card-content {
        justify-content: center;
      }

      .login-error {
        padding: 1rem;
        width: 300px;
        color: white;
        background-color: red;
      }

      .login-buttons {
        display: flex;
        flex-direction: row;
        justify-content: flex-end;
      }
    `,
  ],
  standalone: false,
})
export class LoginFormComponent {
  @Input()
  set pending(isPending: boolean) {
    if (isPending) {
      this.form.disable();
    } else {
      this.form.enable();
    }
  }

  @Input() errorMessage!: string | null;

  @Output() submitted = new EventEmitter<Credentials>();

  form: FormGroup = new FormGroup({
    username: new FormControl('ngrx'),
    password: new FormControl(''),
  });

  submit() {
    if (this.form.valid) {
      this.submitted.emit(this.form.value);
    }
  }
}

import { Component, computed, input } from '@angular/core';
import { ApiMember } from '@ngrx-io/shared';
import { SymbolExcerptComponent } from './symbol-excerpt.component';
import { InlineMarkdownPipe } from './inline-markdown.pipe';

@Component({
  selector: 'ngrx-symbol-params',
  standalone: true,
  imports: [SymbolExcerptComponent, InlineMarkdownPipe],
  template: `
    @for (param of params(); track $index) {
      <div class="param">
        <div class="header">
          @if (param.required) {
            <code class="paramSymbol">{{ '@param' }}</code>
          } @else {
            <code class="paramSymbol">{{ '@optional' }}</code>
          }
          <code class="name">{{ param.name }}</code>
          @if (param.description) {
            <p [innerHtml]="param.description | ngrxInlineMarkdown"></p>
          }
        </div>

        <ngrx-symbol-excerpt [excerptTokens]="param.excerptTokens" />
      </div>
    }
  `,
  styles: [
    `
      :host {
        display: block;
        border-top: 1px solid var(--ngrx-border-color);
      }

      .param {
        display: flex;
        flex-direction: column;
        padding: 8px;
      }

      .header {
        display: grid;
        align-items: center;
        grid-template-columns: 96px 112px 1fr;
        gap: 16px;
      }

      .paramSymbol {
        font-weight: 700;
        color: var(--ngrx-link);
      }

      code {
        font-family: 'Oxanium', sans-serif;
        padding: 0.25em 0.5em;
        border-radius: 4px;
        font-size: 15px;
      }

      p {
        font-size: 13px;
        padding: 0;
        margin: 0;
      }
    `,
  ],
})
export class SymbolParamsComponent {
  symbol = input.required<ApiMember>();
  params = computed(() => {
    const parameters = this.symbol().parameters || [];
    return parameters.map((param) => {
      const docs = this.symbol().docs.params.find(
        (p) => p.name === param.parameterName
      );

      return {
        name: param.parameterName,
        required: !param.isOptional,
        excerptTokens: this.symbol().excerptTokens.slice(
          param.parameterTypeTokenRange.startIndex,
          param.parameterTypeTokenRange.endIndex
        ),
        description: docs?.description || '',
      };
    });
  });
}

import { combineLatest, from, isObservable, Observable } from 'rxjs';
import { distinctUntilChanged } from 'rxjs/operators';

type Primitive = string | number | bigint | boolean | symbol | null | undefined;

type ObservableOrPromise<T> = Observable<T> | PromiseLike<T>;

type ObservableDictionary<PO> = Required<{
  [Key in keyof PO]: Observable<unknown>;
}>;

export type PotentialObservableResult<PO, ExtendedResult = never> =
  PO extends ObservableOrPromise<infer Result>
    ? Result | ExtendedResult
    : PO extends Primitive
      ? PO
      : keyof PO extends never
        ? PO
        : PO extends ObservableDictionary<PO>
          ?
              | {
                  [Key in keyof PO]: PO[Key] extends Observable<infer Value>
                    ? Value
                    : never;
                }
              | ExtendedResult
          : PO;

export function fromPotentialObservable<PO>(
  potentialObservable: PO
): Observable<PotentialObservableResult<PO>> {
  type Result = ReturnType<typeof fromPotentialObservable<PO>>;

  if (isObservable(potentialObservable)) {
    return potentialObservable as Result;
  }

  if (isObservableDictionary(potentialObservable)) {
    return combineLatest(
      toDistinctObsDictionary(potentialObservable)
    ) as Result;
  }

  if (isPromiseLike(potentialObservable)) {
    return from(potentialObservable) as Result;
  }

  return new Observable<PO>((subscriber) => {
    subscriber.next(potentialObservable);
  }) as Result;
}

function isPromiseLike(value: unknown): value is PromiseLike<unknown> {
  return typeof (value as PromiseLike<unknown>)?.then === 'function';
}

function isObservableDictionary(
  value: unknown
): value is Record<string, Observable<unknown>> {
  return (
    isDictionary(value) &&
    Object.keys(value).length > 0 &&
    Object.values(value).every(isObservable)
  );
}

function isDictionary(value: unknown): value is Record<string, unknown> {
  return !!value && typeof value === 'object' && !Array.isArray(value);
}

function toDistinctObsDictionary<
  OD extends Record<string, Observable<unknown>>,
>(obsDictionary: OD): OD {
  return Object.keys(obsDictionary).reduce(
    (acc, key) => ({
      ...acc,
      [key]: obsDictionary[key].pipe(distinctUntilChanged()),
    }),
    {} as OD
  );
}

import * as path from 'path';
import { createRule } from '../../rule-creator';
import {
  getNgRxStores,
  isPropertyDefinition,
  isTSTypeReference,
  isCallExpression,
  isTSInstantiationExpression,
} from '../../utils';
import type { TSESTree } from '@typescript-eslint/utils';

export const noTypedStore = 'noTypedStore';
export const noTypedStoreSuggest = 'noTypedStoreSuggest';

type MessageIds = typeof noTypedStore | typeof noTypedStoreSuggest;
type Options = readonly [];

export default createRule<Options, MessageIds>({
  name: path.parse(__filename).name,
  meta: {
    type: 'suggestion',
    hasSuggestions: true,
    docs: {
      description: 'The global store should not be typed.',
      ngrxModule: 'store',
    },
    schema: [],
    messages: {
      [noTypedStore]:
        '`Store` should not be typed, use `Store` (without generic) instead.',
      [noTypedStoreSuggest]: 'Remove generic from `Store`.',
    },
  },
  defaultOptions: [],
  create: (context) => {
    return {
      Program() {
        const { identifiers = [] } = getNgRxStores(context);

        for (const identifier of identifiers) {
          // using inject()
          if (!identifier.typeAnnotation) {
            const { parent } = identifier;
            if (
              isPropertyDefinition(parent) &&
              parent.value &&
              isCallExpression(parent.value) &&
              parent.value.arguments.length
            ) {
              const [storeArgument] = parent.value.arguments;
              if (isTSInstantiationExpression(storeArgument)) {
                report(storeArgument.typeArguments);
              }
            }

            continue;
          }

          if (
            !isTSTypeReference(identifier.typeAnnotation.typeAnnotation) ||
            !identifier.typeAnnotation.typeAnnotation.typeArguments
          ) {
            continue;
          }

          report(identifier.typeAnnotation.typeAnnotation.typeArguments);
        }
      },
    };

    function report(typeArguments: TSESTree.TSTypeParameterInstantiation) {
      context.report({
        node: typeArguments,
        messageId: noTypedStore,
        suggest: [
          {
            messageId: noTypedStoreSuggest,
            fix: (fixer) => fixer.remove(typeArguments),
          },
        ],
      });
    }
  },
});

import { ActionReducer, Action } from '../models';
import {
  isPlainObject,
  isUndefined,
  isNull,
  isNumber,
  isBoolean,
  isString,
  isArray,
  RUNTIME_CHECK_URL,
  isComponent,
} from './utils';

export function serializationCheckMetaReducer(
  reducer: ActionReducer<any, any>,
  checks: { action: (action: Action) => boolean; state: () => boolean }
): ActionReducer<any, any> {
  return function (state, action) {
    if (checks.action(action)) {
      const unserializableAction = getUnserializable(action);
      throwIfUnserializable(unserializableAction, 'action');
    }

    const nextState = reducer(state, action);

    if (checks.state()) {
      const unserializableState = getUnserializable(nextState);
      throwIfUnserializable(unserializableState, 'state');
    }

    return nextState;
  };
}

function getUnserializable(
  target?: any,
  path: string[] = []
): false | { path: string[]; value: any } {
  // Guard against undefined and null, e.g. a reducer that returns undefined
  if ((isUndefined(target) || isNull(target)) && path.length === 0) {
    return {
      path: ['root'],
      value: target,
    };
  }

  const keys = Object.keys(target);
  return keys.reduce<false | { path: string[]; value: any }>((result, key) => {
    if (result) {
      return result;
    }

    const value = (target as any)[key];

    // Ignore Ivy components
    if (isComponent(value)) {
      return result;
    }

    if (
      isUndefined(value) ||
      isNull(value) ||
      isNumber(value) ||
      isBoolean(value) ||
      isString(value) ||
      isArray(value)
    ) {
      return false;
    }

    if (isPlainObject(value)) {
      return getUnserializable(value, [...path, key]);
    }

    return {
      path: [...path, key],
      value,
    };
  }, false);
}

function throwIfUnserializable(
  unserializable: false | { path: string[]; value: any },
  context: 'state' | 'action'
) {
  if (unserializable === false) {
    return;
  }

  const unserializablePath = unserializable.path.join('.');
  const error: any = new Error(
    `Detected unserializable ${context} at "${unserializablePath}". ${RUNTIME_CHECK_URL}#strict${context}serializability`
  );
  error.value = unserializable.value;
  error.unserializablePath = unserializablePath;
  throw error;
}

import {
  AST_NODE_TYPES,
  ESLintUtils,
  type TSESTree,
} from '@typescript-eslint/utils';
import * as path from 'path';
import { createRule } from '../../rule-creator';
import {
  createEffectExpression,
  isBlockStatement,
  isReturnStatement,
  mapLikeOperatorCallExpressions,
} from '../../utils';

export const messageId = 'noMultipleActionsInEffects';

type MessageIds = typeof messageId;
type Options = readonly unknown[];
type EffectsMapLikeOperatorsReturn =
  | TSESTree.ArrowFunctionExpression
  | TSESTree.CallExpression
  | TSESTree.FunctionExpression
  | TSESTree.ReturnStatement;

export default createRule<Options, MessageIds>({
  name: path.parse(__filename).name,
  meta: {
    type: 'problem',
    docs: {
      description: '`Effect` should not return multiple actions.',
      ngrxModule: 'effects',
      requiresTypeChecking: true,
    },
    schema: [],
    messages: {
      [messageId]: '`Effect` should return a single action.',
    },
  },
  defaultOptions: [],
  create: (context) => {
    return {
      [`${createEffectExpression} ${mapLikeOperatorCallExpressions}`](
        node: EffectsMapLikeOperatorsReturn
      ) {
        const nodeToReport = getNodeToReport(node);
        if (!nodeToReport) {
          return;
        }

        const services = ESLintUtils.getParserServices(context);
        const typeChecker = services.program.getTypeChecker();
        const type = services.getTypeAtLocation(nodeToReport);

        if (typeChecker.isArrayType(type)) {
          context.report({
            node: nodeToReport,
            messageId,
          });
        } else if (
          type.isUnion() &&
          type.types.some((ut) => typeChecker.isArrayType(ut))
        ) {
          context.report({
            node: nodeToReport,
            messageId,
          });
        }
      },
    };
  },
});

function getNodeToReport(node: EffectsMapLikeOperatorsReturn) {
  switch (node.type) {
    case AST_NODE_TYPES.ArrowFunctionExpression:
    case AST_NODE_TYPES.FunctionExpression:
      return isBlockStatement(node.body)
        ? findReturnStatement(node.body.body)
        : node.body;
    case AST_NODE_TYPES.CallExpression:
      return findReturnStatement(node.arguments) ?? node.arguments[0];
    default:
      return node.argument;
  }
}

function findReturnStatement(nodes: TSESTree.Node[]) {
  const returnNode = nodes.find((n): n is TSESTree.ReturnStatement =>
    isReturnStatement(n)
  );
  return returnNode?.argument;
}

import * as ts from 'typescript';
import {
  Tree,
  Rule,
  chain,
  SchematicContext,
} from '@angular-devkit/schematics';
import {
  commitChanges,
  createReplaceChange,
  ReplaceChange,
  visitTSSourceFiles,
} from '../../schematics-core';

export function migrateProvideEffects(): Rule {
  return (tree: Tree, ctx: SchematicContext) => {
    visitTSSourceFiles(tree, (sourceFile) => {
      const changes: ReplaceChange[] = [];

      let isProvideEffectsImported = false;
      visitImportSpecifiers(sourceFile, (node) => {
        if (
          node.name.getText() === 'provideEffects' &&
          node.parent.parent.parent.moduleSpecifier
            .getText()
            .includes('@ngrx/effects')
        ) {
          isProvideEffectsImported = true;
          return;
        }
      });

      if (!isProvideEffectsImported) {
        return;
      }

      visitProvideEffects(sourceFile, (node) => {
        const [effectClasses] = node.arguments;
        if (effectClasses && ts.isArrayLiteralExpression(effectClasses)) {
          const spreaded = effectClasses.elements
            .map((e) => e.getText())
            .join(', ');
          changes.push(
            createReplaceChange(
              sourceFile,
              effectClasses,
              effectClasses.getText(),
              spreaded
            )
          );
        }
      });

      commitChanges(tree, sourceFile.fileName, changes);

      if (changes.length) {
        ctx.logger.info(`[@ngrx/effects] Updated provideEffects usage`);
      }
    });
  };
}

function visitProvideEffects(
  node: ts.Node,
  visitor: (node: ts.CallExpression) => void
) {
  if (
    ts.isCallExpression(node) &&
    ts.isIdentifier(node.expression) &&
    node.expression.text === 'provideEffects'
  ) {
    visitor(node);
  }

  ts.forEachChild(node, (childNode) => visitProvideEffects(childNode, visitor));
}

function visitImportSpecifiers(
  node: ts.Node,
  visitor: (node: ts.ImportSpecifier) => void
) {
  if (ts.isImportSpecifier(node)) {
    visitor(node);
  }

  ts.forEachChild(node, (childNode) =>
    visitImportSpecifiers(childNode, visitor)
  );
}

export default function (): Rule {
  return chain([migrateProvideEffects()]);
}

import { getMode, setMode } from '@stencil/core';
import { printIonWarning } from '@utils/logging';

import type { IonicConfig, Mode } from '../interface';
import { isPlatform, setupPlatforms } from '../utils/platform';

import { config, configFromSession, configFromURL, saveConfig } from './config';

// TODO(FW-2832): types

let defaultMode: Mode;

export const getIonMode = (ref?: any): Mode => {
  return (ref && getMode(ref)) || defaultMode;
};

export const initialize = (userConfig: IonicConfig = {}) => {
  if (typeof (window as any) === 'undefined') {
    return;
  }

  const doc = window.document;
  const win = window;
  const Ionic = ((win as any).Ionic = (win as any).Ionic || {});

  // create the Ionic.config from raw config object (if it exists)
  // and convert Ionic.config into a ConfigApi that has a get() fn
  const configObj = {
    ...configFromSession(win),
    persistConfig: false,
    ...Ionic.config,
    ...configFromURL(win),
    ...userConfig,
  };

  config.reset(configObj);
  if (config.getBoolean('persistConfig')) {
    saveConfig(win, configObj);
  }

  // Setup platforms
  setupPlatforms(win);

  // first see if the mode was set as an attribute on <html>
  // which could have been set by the user, or by pre-rendering
  // otherwise get the mode via config settings, and fallback to md
  Ionic.config = config;
  Ionic.mode = defaultMode = config.get(
    'mode',
    doc.documentElement.getAttribute('mode') || (isPlatform(win, 'ios') ? 'ios' : 'md')
  );
  config.set('mode', defaultMode);
  doc.documentElement.setAttribute('mode', defaultMode);
  doc.documentElement.classList.add(defaultMode);

  if (config.getBoolean('_testing')) {
    config.set('animated', false);
  }

  const isIonicElement = (elm: any) => elm.tagName?.startsWith('ION-');

  const isAllowedIonicModeValue = (elmMode: string) => ['ios', 'md'].includes(elmMode);

  setMode((elm: any) => {
    while (elm) {
      const elmMode = (elm as any).mode || elm.getAttribute('mode');
      if (elmMode) {
        if (isAllowedIonicModeValue(elmMode)) {
          return elmMode;
        } else if (isIonicElement(elm)) {
          printIonWarning('Invalid ionic mode: "' + elmMode + '", expected: "ios" or "md"');
        }
      }
      elm = elm.parentElement;
    }
    return defaultMode;
  });
};

export default initialize;

import {
  BsDatepickerViewMode,
  DatepickerFormatOptions,
  DatepickerRenderOptions,
  DatepickerDateCustomClasses,
  DatepickerDateTooltipText,
  DaysCalendarModel,
  DaysCalendarViewModel,
  MonthsCalendarViewModel,
  MonthViewOptions,
  YearsCalendarViewModel
} from '../models';
import { defaultMonthOptions } from './_defaults';
import { BsDatepickerConfig } from '../bs-datepicker.config';

export interface BsDatepickerViewState {
  date: Date;
  mode: BsDatepickerViewMode;
}

export class BsDatepickerState
  implements DatepickerRenderOptions, DatepickerFormatOptions {
  // date picker
  selectedDate?: Date;
  // daterange picker
  selectedRange?: Date[];
  // time picker
  selectedTime?: Date[];

  // initial date of calendar, today by default
  view?: BsDatepickerViewState;

  isDisabled?: boolean;
  // bounds
  minDate?: Date;
  maxDate?: Date;
  daysDisabled?: number[];
  datesDisabled?: Date[];
  datesEnabled?: Date[];
  minMode?: BsDatepickerViewMode;
  dateCustomClasses?: DatepickerDateCustomClasses[];
  dateTooltipTexts?: DatepickerDateTooltipText[];

  hoveredDate?: Date;
  hoveredMonth?: Date;
  hoveredYear?: Date;

  // days calendar
  monthsModel?: DaysCalendarModel[];
  formattedMonths?: DaysCalendarViewModel[];
  flaggedMonths?: DaysCalendarViewModel[];
  selectFromOtherMonth?: boolean;
  showPreviousMonth?: boolean; // dateRangePicker only;
  preventChangeToNextMonth?: boolean; // dateRangePicker only;
  displayOneMonthRange?: boolean; // dateRangePicker only;

  // months calendar
  monthsCalendar?: MonthsCalendarViewModel[];
